CREATE TABLE IF NOT EXISTS public.gaia_state_help_intents (
    state gaia_state NOT NULL,
    target_help_intents help_intent[] DEFAULT '{}'::help_intent[] NOT NULL
);

CREATE TABLE IF NOT EXISTS realtime.messages (
    topic text NOT NULL,
    extension text NOT NULL,
    payload jsonb,
    event text,
    private boolean DEFAULT false,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    inserted_at timestamp without time zone DEFAULT now() NOT NULL,
    id uuid DEFAULT gen_random_uuid() NOT NULL
);

CREATE TABLE IF NOT EXISTS realtime.schema_migrations (
    version bigint NOT NULL,
    inserted_at timestamp(0) without time zone
);

CREATE OR REPLACE VIEW extensions.pg_stat_statements_info AS  SELECT dealloc,
    stats_reset
   FROM pg_stat_statements_info() pg_stat_statements_info(dealloc, stats_reset);;

CREATE OR REPLACE FUNCTION public.gaia_get_next_recommendation(p_session_id uuid, p_last_shown_position smallint)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_next record;
  v_max_position smallint;
  v_user_id uuid;
begin
  select s.user_id into v_user_id
  from public.sessions s
  where s.id = p_session_id;

  if v_user_id is null then
    raise exception 'Session not found: %', p_session_id;
  end if;

  select coalesce(max(sr.position), 0)
    into v_max_position
  from public.session_recommendations sr
  where sr.session_id = p_session_id;

  if p_last_shown_position >= v_max_position then
    return jsonb_build_object(
      'ok', false,
      'pool_exhausted', true,
      'gaia_copy', 'Ya te mostr├® todo lo que tengo para este momento.',
      'suggestions', jsonb_build_array('sanctuary', 'fuente')
    );
  end if;

  select sr.resource_id, sr.position, sr.layer
    into v_next
  from public.session_recommendations sr
  where sr.session_id = p_session_id
    and sr.position = p_last_shown_position + 1
  limit 1;

  if v_next.resource_id is null then
    return jsonb_build_object(
      'ok', false,
      'pool_exhausted', true,
      'gaia_copy', 'No tengo m├Īs opciones para este momento.',
      'suggestions', jsonb_build_array('sanctuary', 'fuente')
    );
  end if;

  return jsonb_build_object(
    'ok', true,
    'pool_exhausted', false,
    'position', v_next.position,
    'resource_id', v_next.resource_id,
    'gaia_copy', case
      when v_next.layer = 0 then 'Esta tambi├®n puede ayudarte ahora.'
      when v_next.layer <= 2 then 'No es exactamente para esto, pero puede servir.'
      else 'Esto es lo que me queda. No es lo m├Īs espec├Łfico, pero puede ayudar algo.'
    end
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.gaia_get_session_history(p_session_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_data jsonb;
  v_user_id uuid;
begin
  select s.user_id into v_user_id
  from public.sessions s
  where s.id = p_session_id;

  if v_user_id is null then
    raise exception 'Session not found: %', p_session_id;
  end if;

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'position', sr.position,
        'resource_id', sr.resource_id,
        'resource', public.gaia_get_resource_min(sr.resource_id),
        'layer', sr.layer,
        'is_exploration', sr.is_exploration
      )
      order by sr.position
    ),
    '[]'::jsonb
  )
  into v_data
  from public.session_recommendations sr
  where sr.session_id = p_session_id;

  return jsonb_build_object(
    'ok', true,
    'session_id', p_session_id,
    'total', coalesce(jsonb_array_length(v_data), 0),
    'data', v_data
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.gaia_inc_jsonb_weight(weights jsonb, k text, delta integer)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$declare
  cur int;
begin
  cur := coalesce((weights ->> k)::int, 0);
  return jsonb_set(
    weights,
    array[k],
    to_jsonb(cur + delta),
    true
  );
end;$function$

CREATE OR REPLACE FUNCTION public.gaia_submit_session_action(p_session_id uuid, p_chosen_resource_id uuid DEFAULT NULL::uuid, p_feedback feedback_type DEFAULT NULL::feedback_type, p_saved boolean DEFAULT false, p_action gaia_action_type DEFAULT NULL::gaia_action_type)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id         uuid;
  v_state           gaia_state;
  v_area            life_area;
  v_time_bucket     time_bucket;
  v_format          resource_format;
  v_intervention    text;
  v_help_intent     text;
  v_min_step        text;
  v_source_name     text;
  v_fmt_w           jsonb;
  v_hi_w            jsonb;
  v_ik_w            jsonb;
  v_dur_w           jsonb;
  v_new_streak      int;
  v_delta_total     int := 0;
  v_action_feedback gaia_action_type;
  v_evt_meta        jsonb := jsonb_build_object('src', 'gaia_submit_session_action_v6');
begin
  -- Contexto de la sesi├│n (sirve a ambas ramas)
  select s.user_id, s.state, s.area, s.time_bucket
    into v_user_id, v_state, v_area, v_time_bucket
  from public.sessions s
  where s.id = p_session_id;

  if v_user_id is null then
    raise exception 'Session not found: %', p_session_id;
  end if;

  -- ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
  -- RAMA LIVIANA ┬Ę se├▒ales de interacci├│n (opened y afines)
  -- Captura con intervention_key en COLUMNA. Sin tocar pesos.
  -- ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
  if p_action is not null then
    if p_chosen_resource_id is null then
      raise exception '% requiere un resource_id', p_action;
    end if;

    select r.intervention_key into v_intervention
    from public.resources r where r.id = p_chosen_resource_id;

    insert into public.session_events(session_id, user_id, action_type, resource_id, intervention_key, feedback, metadata)
    values (p_session_id, v_user_id, p_action, p_chosen_resource_id, v_intervention, null,
            jsonb_build_object('src', 'gaia_submit_session_action_light'));

    if p_action = 'opened'::gaia_action_type then
      insert into public.resource_stats(resource_id, opened_count, updated_at)
      values (p_chosen_resource_id, 1, now())
      on conflict (resource_id) do update
        set opened_count = coalesce(resource_stats.opened_count, 0) + 1,
            updated_at   = now();
    end if;

    return jsonb_build_object(
      'ok', true, 'action', p_action::text,
      'resource_id', p_chosen_resource_id, 'intervention_key', v_intervention
    );
  end if;

  -- ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
  -- RAMA COMPLETA ┬Ę chosen / feedback / saved (aprendizaje)
  -- ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

  -- Datos del recurso elegido (early: intervention_key va a la COLUMNA)
  if p_chosen_resource_id is not null then
    select r.format, r.intervention_key, r.help_intent::text,
           r.minimum_step, (r.metadata #>> '{source,name}')
      into v_format, v_intervention, v_help_intent, v_min_step, v_source_name
    from public.resources r
    where r.id = p_chosen_resource_id;

    if v_format is null then
      raise exception 'Resource not found: %', p_chosen_resource_id;
    end if;
  end if;

  if p_feedback = 'me_sirvio' then
    v_action_feedback := 'helpful'::gaia_action_type;
  elsif p_feedback = 'no_me_sirvio' then
    v_action_feedback := 'reject'::gaia_action_type;
  else
    v_action_feedback := null;
  end if;

  -- Eventos (append-only). intervention_key en COLUMNA; metadata solo provenance.
  if p_chosen_resource_id is not null then
    insert into public.session_events(session_id, user_id, action_type, resource_id, intervention_key, feedback, metadata)
    values (p_session_id, v_user_id, 'chosen'::gaia_action_type, p_chosen_resource_id, v_intervention, null, v_evt_meta);
  else
    insert into public.session_events(session_id, user_id, action_type, resource_id, intervention_key, feedback, metadata)
    values (p_session_id, v_user_id, 'dismissed'::gaia_action_type, null, null, p_feedback, v_evt_meta);
  end if;

  if v_action_feedback is not null then
    insert into public.session_events(session_id, user_id, action_type, resource_id, intervention_key, feedback, metadata)
    values (p_session_id, v_user_id, v_action_feedback, p_chosen_resource_id, v_intervention, p_feedback, v_evt_meta);
  end if;

  if p_saved = true and p_chosen_resource_id is not null then
    insert into public.session_events(session_id, user_id, action_type, resource_id, intervention_key, feedback, metadata)
    values (p_session_id, v_user_id, 'saved'::gaia_action_type, p_chosen_resource_id, v_intervention, null,
            v_evt_meta || jsonb_strip_nulls(jsonb_build_object('minimum_step_snapshot', v_min_step)));
  end if;

  -- Santuario: guarda el PASO. intervention_key + area en COLUMNAS; snapshot en metadata.
  if p_saved = true and p_chosen_resource_id is not null then
    insert into public.sanctuary_items(user_id, resource_id, intervention_key, area, metadata)
    select v_user_id, p_chosen_resource_id, v_intervention, v_area,
      jsonb_strip_nulls(jsonb_build_object(
        'minimum_step_snapshot', v_min_step,
        'source_name',           v_source_name,
        'help_intent',           v_help_intent,
        'state_when_saved',      v_state
      ))
    where not exists (
      select 1 from public.sanctuary_items si
      where si.user_id = v_user_id and si.resource_id = p_chosen_resource_id
    );
  end if;

  -- Weights
  insert into public.user_weights(user_id) values (v_user_id)
  on conflict (user_id) do nothing;

  select format_weights, help_intent_weights, intervention_key_weights,
         duration_weights, recent_reject_streak
    into v_fmt_w, v_hi_w, v_ik_w, v_dur_w, v_new_streak
  from public.user_weights where user_id = v_user_id;

  -- Streak
  if p_chosen_resource_id is null then
    v_new_streak := v_new_streak + 1;
  elsif p_feedback = 'no_me_sirvio' then
    v_new_streak := v_new_streak + 1;
  elsif p_feedback = 'me_sirvio' then
    v_new_streak := 0;
  end if;

  -- Pesos personales (solo si eligi├│). Mismo delta para los cuatro.
  if p_chosen_resource_id is not null then
    v_delta_total :=
        1
      + case when p_feedback = 'me_sirvio' then 2
             when p_feedback = 'no_me_sirvio' then -2 else 0 end
      + case when p_saved then 2 else 0 end;

    v_fmt_w := public.gaia_inc_jsonb_weight(v_fmt_w, v_format::text, v_delta_total);
    if v_help_intent is not null then
      v_hi_w := public.gaia_inc_jsonb_weight(v_hi_w, v_help_intent, v_delta_total);
    end if;
    if v_intervention is not null then
      v_ik_w := public.gaia_inc_jsonb_weight(v_ik_w, v_intervention, v_delta_total);
    end if;
    v_dur_w := public.gaia_inc_jsonb_weight(v_dur_w, v_time_bucket::text, v_delta_total);
  end if;

  update public.user_weights
    set format_weights           = v_fmt_w,
        help_intent_weights      = v_hi_w,
        intervention_key_weights = v_ik_w,
        duration_weights         = v_dur_w,
        recent_reject_streak     = v_new_streak,
        updated_at               = now()
  where user_id = v_user_id;

  -- resource_stats
  if p_chosen_resource_id is not null then
    insert into public.resource_stats(resource_id, chosen_count, helpful_count, saved_count, updated_at)
    values (
      p_chosen_resource_id, 1,
      case when p_feedback = 'me_sirvio' then 1 else 0 end,
      case when p_saved then 1 else 0 end,
      now()
    )
    on conflict (resource_id) do update
      set chosen_count  = resource_stats.chosen_count + 1,
          helpful_count = resource_stats.helpful_count + case when p_feedback = 'me_sirvio' then 1 else 0 end,
          saved_count   = resource_stats.saved_count   + case when p_saved then 1 else 0 end,
          updated_at    = now();
  end if;

  return jsonb_build_object(
    'ok', true, 'user_id', v_user_id, 'recent_reject_streak', v_new_streak,
    'updated_weights', jsonb_build_object(
      'format_weights', v_fmt_w, 'help_intent_weights', v_hi_w,
      'intervention_key_weights', v_ik_w, 'duration_weights', v_dur_w
    )
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_close_resource_viewer(p_user_id_text text, p_source text DEFAULT ''::text, p_resource_id_text text DEFAULT ''::text, p_session_id_text text DEFAULT ''::text, p_sanctuary_item_id_text text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  if p_source = 'lumi' then
    return public.lumi_get_node('POST_VIEWER_LUMI');
  end if;

  if p_source = 'fuente' then
    if coalesce(p_resource_id_text, '') <> '' then
      return public.lumi_open_resource(
        p_user_id_text,
        p_resource_id_text,
        'fuente',
        coalesce(p_session_id_text, '')
      );
    end if;

    return public.lumi_get_fuente_items('', '', '');
  end if;

  if p_source = 'sanctuary' then
    if coalesce(p_sanctuary_item_id_text, '') <> '' then
      return public.lumi_open_sanctuary_item(
        p_user_id_text,
        p_sanctuary_item_id_text
      );
    end if;

    if coalesce(p_resource_id_text, '') <> '' then
      return public.lumi_open_resource(
        p_user_id_text,
        p_resource_id_text,
        'sanctuary',
        coalesce(p_session_id_text, '')
      );
    end if;

    return public.lumi_get_sanctuary(p_user_id_text);
  end if;

  return public.lumi_get_node('HOME_DEFAULT');
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_close_resource_viewer(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_source       text;
  v_user_id      uuid;
  v_resource_id  uuid;
  v_session_id   uuid;
  v_node_code    text;
  v_node         jsonb;
  v_module_color text;
  v_message      text;
  v_card         jsonb;
  v_after_prompt text;
BEGIN
  v_source      := coalesce(nullif(trim(p_params->>'source'), ''), 'lumi');
  v_user_id     := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_resource_id := nullif(trim(p_params->>'resource_id'), '')::uuid;
  v_session_id  := nullif(trim(p_params->>'session_id'), '')::uuid;

  v_node_code := CASE v_source
    WHEN 'fuente'    THEN 'POST_VIEWER_FUENTE'
    WHEN 'sanctuary' THEN 'POST_VIEWER_SANCTUARY'
    ELSE 'POST_VIEWER_LUMI'
  END;

  v_module_color := CASE v_source
    WHEN 'fuente'    THEN '#2A9068'
    WHEN 'sanctuary' THEN '#B88820'
    ELSE '#7860E0'
  END;

  v_node := public.lumi_get_node(v_node_code);

  IF v_node IS NULL THEN
    RETURN public.lumi_get_node('HOME_DEFAULT')
      || jsonb_build_object(
        'ok', false,
        'error', 'node_not_found',
        'state', jsonb_build_object('contentSource', '', 'moduleColor', '#7860E0')
      );
  END IF;

  -- Mensaje base del nodo
  v_message := coalesce(v_node->>'message', 'Listo.');

  -- ŌŚĆ NUEVO: solo desde LUMI y con recurso, usar el after_prompt del recurso
  IF v_source = 'lumi' AND v_resource_id IS NOT NULL THEN
    BEGIN
      v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);
      v_after_prompt := nullif(trim(v_card->>'after_prompt'), '');
      IF v_after_prompt IS NOT NULL THEN
        v_message := v_after_prompt;   -- la pregunta espec├Łfica del recurso
      END IF;
    EXCEPTION WHEN OTHERS THEN
      -- Si falla el lookup, queda el mensaje base del nodo. Nunca rompe el cierre.
      NULL;
    END;
  END IF;

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         v_node_code,
    'message',      v_message,
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'empty_presence',
    'content',      jsonb_build_object('type', 'empty_presence'),
    'state',        jsonb_build_object(
                      'contentSource',     v_source,
                      'moduleColor',       v_module_color,
                      'currentResourceId', coalesce(v_resource_id::text, ''),
                      'currentSessionId',  coalesce(v_session_id::text, '')
                    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_confirm_remove_from_sanctuary(p_user_id_text text, p_sanctuary_item_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id           uuid;
  v_sanctuary_item_id uuid;
  v_detail            jsonb;
  v_node              jsonb;
BEGIN
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_sanctuary_item_id := nullif(
    trim(both '''' from trim(coalesce(p_sanctuary_item_id_text, ''))),
    ''
  )::uuid;

  v_detail := public.lumi_open_sanctuary_item(p_user_id_text, p_sanctuary_item_id_text);
  v_node   := public.lumi_get_node('SANCTUARY_REMOVE_CONFIRM');

  RETURN jsonb_build_object(
    'ok', true,
    'code', 'SANCTUARY_REMOVE_CONFIRM',
    'message', coalesce(v_node->>'message', '┬┐Quer├®s quitar esto de tu Santuario?'),
    'actions', jsonb_build_array(
      jsonb_build_object(
        'label',  'S├Ł, quitar',
        'action', 'remove_from_sanctuary',  -- ŌŚĆ FIX: era confirm_remove (loop)
        'value',  v_sanctuary_item_id::text
      ),
      jsonb_build_object(
        'label',  'No, volver',
        'action', 'open_sanctuary',
        'value',  ''
      )
    ),
    'content_type', 'sanctuary_detail',
    'content', coalesce(v_detail->'content', '{}'::jsonb),
    'state',   coalesce(v_detail->'state', '{}'::jsonb) ||
               jsonb_build_object(
                 'contentSource',   'sanctuary',
                 'moduleColor',     '#C8A46E',
                 'spacesMenuOpen',  false,
                 'filterPanelOpen', false
               )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_feedback_helpful(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id     uuid;
  v_session_id  uuid;
  v_resource_id uuid;
  v_node        jsonb;
  v_card        jsonb;
BEGIN
  v_user_id     := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_session_id  := nullif(trim(p_params->>'session_id'), '')::uuid;
  v_resource_id := nullif(trim(p_params->>'resource_id'), '')::uuid;

  IF v_session_id IS NULL OR v_resource_id IS NULL THEN
    RETURN public.lumi_get_node('HOME_DEFAULT')
      || jsonb_build_object(
           'ok',    false,
           'error', 'missing_session_or_resource_for_feedback',
           'state', '{}'::jsonb
         );
  END IF;

  -- 1) Registrar feedback positivo (gaia aprende)
  PERFORM public.gaia_submit_session_action(
    p_session_id         := v_session_id,
    p_chosen_resource_id := v_resource_id,
    p_feedback           := 'me_sirvio'::feedback_type,
    p_saved              := false
  );

  -- 2) Hidratar el resource_card del recurso evaluado
  v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);

  -- 3) Routear al nodo can├│nico
  v_node := public.lumi_get_node('RESOURCE_FEEDBACK_HELPFUL');

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'RESOURCE_FEEDBACK_HELPFUL',
    'message',      coalesce(v_node->>'message', 'Me alegra que haya servido.'),
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'resource_card',
    'content',      coalesce(v_card, '{}'::jsonb) || jsonb_build_object(
                      'type',        'resource_card',
                      'resource_id', v_resource_id::text,
                      'session_id',  v_session_id::text,
                      'is_from',     'lumi'
                    ),
    'state',        jsonb_build_object(
                      'currentResourceId',  v_resource_id::text,
                      'contentSource',      'lumi'
                    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_feedback_reject(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_session_id  uuid;
  v_resource_id uuid;
  v_node        jsonb;
  v_reflection  text;
BEGIN
  v_session_id  := nullif(trim(p_params->>'session_id'), '')::uuid;
  v_resource_id := nullif(trim(p_params->>'resource_id'), '')::uuid;

  IF v_session_id IS NULL OR v_resource_id IS NULL THEN
    RETURN public.lumi_get_node('HOME_DEFAULT')
      || jsonb_build_object('ok', false,
                            'error', 'missing_session_or_resource_for_feedback',
                            'state', '{}'::jsonb);
  END IF;

  PERFORM public.gaia_submit_session_action(
    p_session_id         := v_session_id,
    p_chosen_resource_id := v_resource_id,
    p_feedback           := 'no_me_sirvio'::feedback_type,
    p_saved              := false
  );

  v_node       := public.lumi_get_node('RESOURCE_FEEDBACK_REJECT');
  v_reflection := public.lumi_get_message('reflection', 'after_action');

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'RESOURCE_FEEDBACK_REJECT',
    'message',      coalesce(v_reflection, v_node->>'message', 'Entendido.'),
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'empty_presence',
    'content',      jsonb_build_object('type', 'empty_presence'),
    'state',        '{}'::jsonb
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_get_fuente_items(p_area text DEFAULT ''::text, p_formato text DEFAULT ''::text, p_duracion text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_items              jsonb;
  v_count              integer := 0;
  v_has_filters        boolean;
  v_filter_parts       text[]  := ARRAY[]::text[];
  v_filter_label       text    := '';
  v_node_code          text;
  v_node               jsonb;
  v_message            text;
  v_empty              text;
  v_area_options       jsonb;
  v_format_options     jsonb;
  v_duration_options   jsonb;
BEGIN
  v_has_filters :=
    coalesce(nullif(trim(p_area), ''), '')    <> ''
    OR coalesce(nullif(trim(p_formato), ''), '')  <> ''
    OR coalesce(nullif(trim(p_duracion), ''), '') <> '';

  IF coalesce(nullif(trim(p_area), ''), '') <> '' THEN
    v_filter_parts := array_append(v_filter_parts, public.lumi_area_label(p_area));
  END IF;
  IF coalesce(nullif(trim(p_formato), ''), '') <> '' THEN
    v_filter_parts := array_append(v_filter_parts, coalesce(
      (SELECT short_label FROM public.ui_copy
        WHERE domain = 'resource_format' AND key = p_formato AND lang = 'es' LIMIT 1),
      p_formato
    ));
  END IF;
  IF coalesce(nullif(trim(p_duracion), ''), '') <> '' THEN
    v_filter_parts := array_append(v_filter_parts,
      CASE p_duracion
        WHEN 't2_5'    THEN 'hasta 5 min'
        WHEN 't5_15'   THEN '5 a 15 min'
        WHEN 't15_plus' THEN 'm├Īs de 15 min'
        ELSE p_duracion
      END);
  END IF;
  v_filter_label := array_to_string(v_filter_parts, ' ┬Ę ');

  SELECT jsonb_agg(jsonb_build_object('value', uc.key, 'label', uc.short_label)
                   ORDER BY uc.sort_order)
    INTO v_area_options
    FROM public.ui_copy uc WHERE uc.domain = 'area' AND uc.lang = 'es';

  SELECT jsonb_agg(jsonb_build_object('value', uc.key, 'label', uc.short_label)
                   ORDER BY uc.sort_order)
    INTO v_format_options
    FROM public.ui_copy uc WHERE uc.domain = 'resource_format' AND uc.lang = 'es';

  SELECT jsonb_agg(jsonb_build_object('value', uc.key, 'label', uc.short_label)
                   ORDER BY uc.sort_order)
    INTO v_duration_options
    FROM public.ui_copy uc WHERE uc.domain = 'time_bucket' AND uc.lang = 'es';

  SELECT
    coalesce(jsonb_agg(
      jsonb_build_object(
        'id',          r.id::text,
        'title',       coalesce(r.title, 'Recurso'),
        'subtitle',
          coalesce(
            (SELECT short_label FROM public.ui_copy
              WHERE domain = 'resource_format' AND key = r.format::text AND lang = 'es' LIMIT 1),
            r.format::text
          ) || ' ┬Ę ' || r.duration_min::text || ' min',
        'action',      'open_resource',
        'value',       'fuente',
        'source_kind', coalesce(r.source_kind, 'external_url'),
        'url',         coalesce(r.url, '')
      )
      ORDER BY r.title
    ), '[]'::jsonb),
    count(*)
  INTO v_items, v_count
  FROM public.resources r
  WHERE r.is_active = true
    AND r.tier = 'A'
    AND CASE WHEN coalesce(nullif(trim(p_area), ''), '') <> ''
          THEN p_area = ANY(r.areas::text[]) ELSE true END
    AND CASE WHEN coalesce(nullif(trim(p_formato), ''), '') <> ''
          THEN r.format::text = p_formato ELSE true END
    AND CASE
          WHEN p_duracion = 't2_5'    THEN r.duration_min <= 5
          WHEN p_duracion = 't5_15'   THEN r.duration_min > 5  AND r.duration_min <= 15
          WHEN p_duracion = 't15_plus' THEN r.duration_min > 15
          ELSE true
        END;

  -- Fuente totalmente vac├Ła (caso raro: 0 recursos sin filtros) ŌåÆ cat├Īlogo
  IF v_count = 0 AND NOT v_has_filters THEN
    v_empty := public.lumi_get_message('empty', 'empty_state');
    v_node  := public.lumi_get_node('FUENTE_EMPTY');
    RETURN jsonb_build_object(
      'ok',           true,
      'code',         'FUENTE_EMPTY',
      'message',      coalesce(v_empty, v_node->>'message', 'No encontr├® recursos.'),
      'actions',      coalesce(v_node->'actions', '[]'::jsonb),
      'content_type', 'empty_presence',
      'content',      jsonb_build_object('type', 'empty_presence', 'source', 'fuente'),
      'state',        jsonb_build_object('contentSource', 'fuente',
                                         'moduleColor', '#2A9068')
    );
  END IF;

  v_message := CASE
    WHEN v_count = 0 AND v_has_filters THEN 'Sin recursos con estos filtros. Prob├Ī ajustar.'
    WHEN v_has_filters THEN v_filter_label || ' ┬Ę ' || v_count::text || ' recursos.'
    ELSE 'Explor├Ī libremente. ' || v_count::text || ' recursos disponibles.'
  END;

  v_node_code := 'FUENTE_DEFAULT';
  v_node      := public.lumi_get_node(v_node_code);

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         v_node_code,
    'message',      v_message,
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'item_list',
    'content', jsonb_build_object(
      'type',   'item_list',
      'source', 'fuente',
      'items',  v_items,
      'current_filters', jsonb_build_object(
        'area',     coalesce(nullif(trim(p_area), ''), ''),
        'format',   coalesce(nullif(trim(p_formato), ''), ''),
        'duration', coalesce(nullif(trim(p_duracion), ''), '')
      ),
      'filter_options', jsonb_build_object(
        'area',     coalesce(v_area_options, '[]'::jsonb),
        'format',   coalesce(v_format_options, '[]'::jsonb),
        'duration', coalesce(v_duration_options, '[]'::jsonb)
      )
    ),
    'state', jsonb_build_object(
      'contentSource', 'fuente',
      'moduleColor',   '#2A9068'
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_get_init_data(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_has_visited     boolean;
  v_sanctuary_count integer;
  v_days_since      integer;
BEGIN
  SELECT coalesce(u.has_visited, false) INTO v_has_visited
  FROM public.users u WHERE u.id = p_user_id;

  SELECT count(*) INTO v_sanctuary_count
  FROM public.sanctuary_items si WHERE si.user_id = p_user_id;

  -- D├Łas desde la ├║ltima sesi├│n (0 si nunca tuvo sesi├│n)
  SELECT coalesce(
    extract(day FROM (now() - max(s.created_at)))::integer, 0
  ) INTO v_days_since
  FROM public.sessions s WHERE s.user_id = p_user_id;

  RETURN jsonb_build_object(
    'has_visited',            v_has_visited,
    'sanctuary_count',        v_sanctuary_count,
    'days_since_last_session', v_days_since
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_get_session_history(p_user_id_text text, p_session_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_session_id uuid;
  v_node jsonb;
  v_items jsonb;
begin
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_session_id := nullif(trim(both '''' from trim(coalesce(p_session_id_text, ''))), '')::uuid;

  if v_session_id is null then
    select s.id
    into v_session_id
    from public.sessions s
    where s.user_id = v_user_id
      and s.mode = 'propose'
    order by s.created_at desc
    limit 1;
  end if;

  v_node := public.lumi_get_node('REC_HISTORY');

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'id', r.id::text,
        'title', r.title,
        'subtitle', concat(r.format::text, ' ┬Ę ', r.duration_min::text, ' min'),
        'format', r.format::text,
        'duration_min', r.duration_min,
        'source_kind', coalesce(r.source_kind, 'external_url'),
        'url', coalesce(r.url, ''),
        'action', 'open_resource',
        'value', 'lumi'
      )
      order by sr.position asc
    ),
    '[]'::jsonb
  )
  into v_items
  from public.session_recommendations sr
  join public.resources r on r.id = sr.resource_id
  where sr.session_id = v_session_id;

  return jsonb_build_object(
    'ok', true,
    'code', 'REC_HISTORY',
    'message', coalesce(v_node->>'message', 'Todo lo que te propuse en esta sesi├│n.'),
    'actions', coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'item_list',
    'content', jsonb_build_object(
      'type', 'item_list',
      'source', 'session_history',
      'items', v_items
    ),
    'state', jsonb_build_object(
      'currentSessionId', coalesce(v_session_id::text, ''),
      'contentSource', 'lumi'
    )
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_go_home(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id         uuid;
  v_has_visited     boolean := true;
  v_first_name      text;
  v_days_since      integer := 0;
  v_sanctuary_count integer := 0;
  v_greeting        text;
  v_culture_phrase  text;
  v_node            jsonb;
  v_si_resource_id  uuid;
  v_si_title        text;
  v_si_format       text;
  v_si_duration     int;
  v_subtitle        text;
  v_offer_item      jsonb;
  v_name_suffix     text;
BEGIN
  v_user_id    := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_days_since := coalesce(nullif(trim(p_params->>'days_since_last_session'), ''), '0')::integer;

  IF v_user_id IS NOT NULL THEN
    SELECT coalesce(u.has_visited, false), u.first_name 
      INTO v_has_visited, v_first_name
    FROM public.users u WHERE u.id = v_user_id;
    SELECT count(*) INTO v_sanctuary_count
    FROM public.sanctuary_items si WHERE si.user_id = v_user_id;
  END IF;

  v_culture_phrase := public.lumi_get_message('culture_phrase', 'first_contact');
  v_name_suffix := CASE 
    WHEN v_first_name IS NOT NULL AND length(trim(v_first_name)) > 0 
    THEN ', ' || trim(v_first_name) ELSE '' END;

  -- Primera visita ŌåÆ prompt de nombre
  IF NOT v_has_visited THEN
    v_node := public.lumi_get_node('HOME_FIRST_VISIT_NAME');
    RETURN jsonb_build_object(
      'ok',           true,
      'code',         'HOME_FIRST_VISIT_NAME',
      'message',      coalesce(v_node->>'message', 
        'Hola. Antes de empezar ŌĆö si quer├®s, decime c├│mo te llamo.'),
      'actions',      coalesce(v_node->'actions', '[]'::jsonb),
      'content_type', 'name_prompt',
      'content',      jsonb_build_object(
                        'type', 'name_prompt',
                        'culture_phrase', coalesce(v_culture_phrase, '')
                      ),
      'state', jsonb_build_object(
        'contentSource', '', 'moduleColor', '#7860E0',
        'currentSessionId', '', 'currentResourceId', '', 'currentSanctuaryItemId', ''
      )
    );
  END IF;

  -- Returning con Santuario ŌåÆ mensaje c├Īlido con nombre
  IF v_has_visited AND v_sanctuary_count > 0 THEN
    SELECT si.resource_id, r.title, r.format::text, r.duration_min
      INTO v_si_resource_id, v_si_title, v_si_format, v_si_duration
    FROM public.sanctuary_items si
    JOIN public.resources r ON r.id = si.resource_id
    WHERE si.user_id = v_user_id
    ORDER BY si.created_at DESC LIMIT 1;

    v_node := public.lumi_get_node('HOME_RETURNING');
    v_greeting := 'Qu├® bueno tenerte de vuelta' || v_name_suffix || '. '
                  || 'Dej├® cerca algo que ya te hizo bien, por si quer├®s retomarlo ŌĆö '
                  || 'o empezamos por donde est├®s hoy.';
    v_subtitle := initcap(coalesce(v_si_format, ''))
                  || coalesce(' ┬Ę ' || v_si_duration || ' min', '');
    v_offer_item := jsonb_build_object(
      'id', v_si_resource_id::text, 'title', v_si_title,
      'subtitle', nullif(v_subtitle, ''), 'format', v_si_format,
      'action', 'open_resource', 'value', 'sanctuary'
    );

    RETURN jsonb_build_object(
      'ok',           true,
      'code',         'HOME_RETURNING',
      'message',      v_greeting,
      'actions',      coalesce(v_node->'actions', '[]'::jsonb),
      'content_type', 'item_list',
      'content',      jsonb_build_object(
                        'type', 'item_list',
                        'culture_phrase', coalesce(v_culture_phrase, ''),
                        'items', jsonb_build_array(v_offer_item)
                      ),
      'state', jsonb_build_object(
        'contentSource', '', 'moduleColor', '#7860E0',
        'currentSessionId', '', 'currentResourceId', '', 'currentSanctuaryItemId', ''
      )
    );
  END IF;

  -- Returning sin Santuario
  IF v_days_since > 7 THEN
    v_greeting := 'Qu├® bueno volver' || v_name_suffix || '. Podemos empezar suave.';
  ELSE
    v_greeting := 'Estoy ac├Ī' || v_name_suffix || '.';
  END IF;

  v_node := public.lumi_get_node('HOME_DEFAULT');

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'HOME_DEFAULT',
    'message',      coalesce(v_greeting, v_node->>'message', 'Estoy ac├Ī.'),
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'empty_presence',
    'content',      jsonb_build_object(
                      'type', 'empty_presence',
                      'culture_phrase', coalesce(v_culture_phrase, '')
                    ),
    'state', jsonb_build_object(
      'contentSource', '', 'moduleColor', '#7860E0',
      'currentSessionId', '', 'currentResourceId', '', 'currentSanctuaryItemId', ''
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_mode_presence(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node    jsonb;
  v_message text;
BEGIN
  v_node := public.lumi_get_node('HOME_PRESENCE');

  -- Asimetr├Ła enriquecedora: a veces LUMI te abraza, a veces te
  -- ofrece una pausa de sabidur├Ła.
  IF random() < 0.5 THEN
    v_message := public.lumi_get_message('support', 'companion');
  ELSE
    v_message := public.lumi_get_message('quote', 'wisdom');
  END IF;

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'HOME_PRESENCE',
    'message',      coalesce(v_message, v_node->>'message', 'Ac├Ī estoy.'),
    'actions',      coalesce(v_node->'actions',
                             jsonb_build_array(
                               jsonb_build_object('label', 'Volver al inicio',
                                                  'action', 'go_home')
                             )),
    'content_type', 'empty_presence',
    'content',      jsonb_build_object('type', 'empty_presence'),
    'state',        jsonb_build_object(
                      'contentSource', '',
                      'moduleColor',   '#7860E0'
                    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_mode_presence(p_user_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_session jsonb;
  v_session_id text := '';
  v_node jsonb;
begin
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;

  begin
    v_session := public.gaia_create_session_and_recommendations(
      v_user_id,
      'presence'::gaia_mode,
      null,
      null,
      null
    );

    v_session_id := coalesce(v_session->>'session_id', '');
  exception when others then
    v_session_id := '';
  end;

  v_node := public.lumi_get_node('HOME_PRESENCE');

  return v_node || jsonb_build_object(
    'state', jsonb_build_object(
      'currentSessionId', v_session_id,
      'contentSource', '',
      'spacesMenuOpen', false,
      'filterPanelOpen', false
    )
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_next_recommendation(p_user_id_text text, p_session_id_text text, p_current_resource_id_text text DEFAULT ''::text, p_last_position integer DEFAULT 1)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_session_id uuid;
  v_current_resource_id uuid;
  v_last_position int;
  v_next jsonb;
  v_resource_id uuid;
  v_card jsonb;
  v_node jsonb;
begin
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_session_id := nullif(trim(both '''' from trim(coalesce(p_session_id_text, ''))), '')::uuid;
  v_current_resource_id := nullif(trim(both '''' from trim(coalesce(p_current_resource_id_text, ''))), '')::uuid;

  if v_session_id is null then
    select s.id
    into v_session_id
    from public.sessions s
    where s.user_id = v_user_id
      and s.mode = 'propose'
    order by s.created_at desc
    limit 1;
  end if;

  if v_session_id is null then
    return public.lumi_get_node('REC_POOL_EXHAUSTED');
  end if;

  select sr.position
  into v_last_position
  from public.session_recommendations sr
  where sr.session_id = v_session_id
    and sr.resource_id = v_current_resource_id
  limit 1;

  v_last_position := coalesce(v_last_position, p_last_position, 1);

  v_next := public.gaia_get_next_recommendation(
    v_session_id,
    v_last_position::smallint
  );

  if v_next is null
     or coalesce((v_next->>'pool_exhausted')::boolean, false)
     or nullif(v_next->>'resource_id', '') is null then
    return public.lumi_get_node('REC_POOL_EXHAUSTED');
  end if;

  v_resource_id := (v_next->>'resource_id')::uuid;
  v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);
  v_node := public.lumi_get_node('REC_NEXT');

  return jsonb_build_object(
    'ok', true,
    'code', 'REC_NEXT',
    'message', coalesce(v_next->>'gaia_copy', v_node->>'message'),
    'actions', coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'resource_card',
    'content', coalesce(v_card, '{}'::jsonb) ||
      jsonb_build_object(
        'type', 'resource_card',
        'resource_id', v_resource_id::text,
        'session_id', v_session_id::text,
        'is_from', 'lumi'
      ),
    'state', jsonb_build_object(
      'currentSessionId', v_session_id::text,
      'currentResourceId', v_resource_id::text,
      'lastRecommendationPosition', (v_next->>'position')::int,
      'resourceSourceKind', coalesce(v_card->>'source_kind', 'external_url'),
      'activeUrl', coalesce(v_card->>'url', ''),
      'contentSource', 'lumi'
    )
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_faros(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id uuid;
  v_faros   jsonb;
  v_node    jsonb;
BEGIN
  v_user_id := nullif(trim(p_params->>'user_id'), '')::uuid;

  IF v_user_id IS NULL THEN
    RETURN public.lumi_get_node('HOME_DEFAULT')
      || jsonb_build_object('ok', false, 'error', 'missing_user_id', 'state', '{}'::jsonb);
  END IF;

  -- Para cada ├Īrea can├│nica de ui_copy, traer el faro_text si existe
  SELECT jsonb_agg(
    jsonb_build_object(
      'area',      uc.key,
      'label',     uc.short_label,
      'hint',      uc.subtitle,
      'faro_text', coalesce(uaf.faro_text, ''),
      'has_faro',  uaf.faro_text IS NOT NULL AND uaf.faro_text <> ''
    ) ORDER BY uc.sort_order
  ) INTO v_faros
  FROM public.ui_copy uc
  LEFT JOIN public.user_area_faros uaf
    ON uaf.user_id = v_user_id
   AND uaf.area::text = uc.key
  WHERE uc.domain = 'area' AND uc.lang = 'es';

  v_node := public.lumi_get_node('FAROS_VIEW');

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'FAROS_VIEW',
    'message',      coalesce(v_node->>'message',
                             'Tus orientaciones ├Łntimas. Solo vos las ves.'),
    'actions',      coalesce(v_node->'actions',
                             jsonb_build_array(
                               jsonb_build_object(
                                 'label',  'Volver al Santuario',
                                 'action', 'open_sanctuary'
                               )
                             )),
    'content_type', 'faros_panel',
    'content',      jsonb_build_object(
                      'type',  'faros_panel',
                      'faros', coalesce(v_faros, '[]'::jsonb),
                      'privacy_hint', 'Solo vos pod├®s leer estos textos. LUMI no los usa.'
                    ),
    'state',        jsonb_build_object(
                      'contentSource', 'sanctuary',
                      'moduleColor',   '#B88820'
                    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_note_editor(p_user_id_text text, p_resource_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_resource_id uuid;
  v_node jsonb;
  v_item record;
begin
  if nullif(trim(coalesce(p_user_id_text, '')), '') is null then
    return public.lumi_get_node('SANCTUARY_WITH_ITEMS');
  end if;

  if nullif(trim(both '''' from trim(coalesce(p_resource_id_text, ''))), '') is null then
    return public.lumi_get_node('SANCTUARY_WITH_ITEMS');
  end if;

  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_resource_id := nullif(
    trim(both '''' from trim(coalesce(p_resource_id_text, ''))),
    ''
  )::uuid;

  select
    si.id as sanctuary_item_id,
    si.note,
    si.area,
    r.title
  into v_item
  from public.sanctuary_items si
  join public.resources r on r.id = si.resource_id
  where si.user_id = v_user_id
    and si.resource_id = v_resource_id
  limit 1;

  if not found then
    return public.lumi_get_node('SANCTUARY_WITH_ITEMS');
  end if;

  v_node := public.lumi_get_node('SANCTUARY_NOTE');

  return jsonb_build_object(
    'ok', true,
    'code', 'SANCTUARY_NOTE',
    'message', coalesce(v_node->>'message', 'Pod├®s dejar una nota para vos.'),
    'actions', coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'note_editor',
    'content', jsonb_build_object(
      'type', 'note_editor',
      'resource_id', v_resource_id::text,
      'sanctuary_item_id', coalesce(v_item.sanctuary_item_id::text, ''),
      'title', coalesce(v_item.title, 'Recurso'),
      'current_note', coalesce(v_item.note, ''),
      'current_area', coalesce(v_item.area::text, '')
    ),
    'state', jsonb_build_object(
      'contentSource', 'sanctuary',
      'moduleColor', '#C8A46E',
      'spacesMenuOpen', false,
      'filterPanelOpen', false
    )
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_note_editor(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_result  jsonb;
  v_options jsonb;
BEGIN
  v_result := public.lumi_open_note_editor(
    p_params->>'user_id',
    p_params->>'resource_id'
  );

  -- Hidratar las 6 ├Īreas desde ui_copy
  SELECT jsonb_agg(
    jsonb_build_object(
      'value', uc.key,
      'label', uc.short_label,
      'hint',  uc.subtitle
    ) ORDER BY uc.sort_order
  ) INTO v_options
  FROM public.ui_copy uc
  WHERE uc.domain = 'area' AND uc.lang = 'es';

  -- Inyectar en content.area_options
  v_result := jsonb_set(
    v_result,
    '{content,area_options}',
    coalesce(v_options, '[]'::jsonb)
  );

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_resource(p_user_id_text text, p_resource_id_text text, p_source text DEFAULT 'fuente'::text, p_session_id_text text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_resource_id uuid;
  v_session_id uuid;
  v_session_text text;
  v_card jsonb;
  v_node_code text;
  v_node jsonb;
begin
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_resource_id := nullif(trim(p_resource_id_text), '')::uuid;
  v_session_text := trim(both '''' from trim(coalesce(p_session_id_text, '')));
  v_session_id := case when v_session_text = '' then null else v_session_text::uuid end;

  -- Registrar apertura (solo si hay sesi├│n). reopened diferido: siempre 'opened'.
  IF v_session_id IS NOT NULL AND v_resource_id IS NOT NULL THEN
    PERFORM public.gaia_submit_session_action(
      p_session_id         := v_session_id,
      p_chosen_resource_id := v_resource_id,
      p_feedback           := NULL,
      p_saved              := false,
      p_action             := 'opened'::gaia_action_type
    );
  END IF;

  v_card := public.gaia_get_resource_card(v_user_id, v_resource_id, v_session_id);

  v_node_code := case
    when p_source = 'lumi' then 'RESOURCE_FROM_LUMI'
    when p_source = 'sanctuary' then 'RESOURCE_FROM_SANCTUARY'
    else 'RESOURCE_FROM_FUENTE'
  end;
  v_node := public.lumi_get_node(v_node_code);

  return jsonb_build_object(
    'ok', true,
    'code', v_node_code,
    'message', coalesce(v_card->>'lumi_context', v_node->>'message'),
    'actions', coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'resource_card',
    'content', coalesce(v_card, '{}'::jsonb) ||
      jsonb_build_object('type', 'resource_card', 'resource_id', v_resource_id::text,
        'session_id', coalesce(v_session_id::text, ''), 'is_from', p_source),
    'state', jsonb_build_object(
      'currentResourceId', v_resource_id::text,
      'resourceSourceKind', coalesce(v_card->>'source_kind', 'external_url'),
      'activeUrl', coalesce(v_card->>'url', ''),
      'contentSource', p_source)
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_sanctuary(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id          uuid := (p_params->>'user_id')::uuid;
  v_area             text := coalesce(nullif(trim(p_params->>'filter_area'), ''), '');
  v_format           text := coalesce(nullif(trim(p_params->>'filter_format'), ''), '');
  v_has_note         text := coalesce(nullif(trim(p_params->>'filter_has_note'), ''), '');
  v_items            jsonb;
  v_count            integer := 0;
  v_total            integer := 0;
  v_has_filters      boolean;
  v_node_code        text;
  v_node             jsonb;
  v_message          text;
  v_empty            text;
  v_area_options     jsonb;
  v_format_options   jsonb;
  v_has_note_options jsonb;
BEGIN
  v_has_filters := v_area <> '' OR v_format <> '' OR v_has_note <> '';

  SELECT count(*) INTO v_total
  FROM public.sanctuary_items
  WHERE user_id = v_user_id;

  -- Santuario completamente vac├Ło ŌåÆ mensaje del cat├Īlogo
  IF v_total = 0 THEN
    v_node  := public.lumi_get_node('SANCTUARY_EMPTY');
    v_empty := public.lumi_get_message('empty', 'empty_state');
    RETURN jsonb_build_object(
      'ok',           true,
      'code',         'SANCTUARY_EMPTY',
      'message',      coalesce(v_empty, v_node->>'message', 'Todav├Ła no guardaste nada.'),
      'actions',      coalesce(v_node->'actions', '[]'::jsonb),
      'content_type', 'empty_presence',
      'content',      jsonb_build_object('type', 'empty_presence', 'source', 'sanctuary'),
      'state',        jsonb_build_object('contentSource', 'sanctuary',
                                         'moduleColor', '#B88820')
    );
  END IF;

  -- Items con filtros aplicados
  SELECT
    coalesce(jsonb_agg(jsonb_build_object(
      'id',       si.id::text,
      'title',    r.title,
      'subtitle',
        coalesce(
          (SELECT short_label FROM public.ui_copy
            WHERE domain = 'resource_format' AND key = r.format::text AND lang = 'es' LIMIT 1),
          r.format::text
        )
        || CASE WHEN si.area IS NOT NULL THEN ' ┬Ę ' || public.lumi_area_label(si.area::text) ELSE '' END
        || CASE WHEN si.note IS NOT NULL AND si.note <> '' THEN ' ┬Ę con nota' ELSE '' END,
      'format',   r.format::text,
      'area',     coalesce(si.area::text, ''),
      'has_note', (si.note IS NOT NULL AND si.note <> ''),
      'action',   'open_sanctuary_item'
    ) ORDER BY si.created_at DESC), '[]'::jsonb),
    count(*)
  INTO v_items, v_count
  FROM public.sanctuary_items si
  JOIN public.resources r ON r.id = si.resource_id
  WHERE si.user_id = v_user_id
    AND CASE WHEN v_area <> '' THEN si.area::text = v_area ELSE true END
    AND CASE WHEN v_format <> '' THEN r.format::text = v_format ELSE true END
    AND CASE
          WHEN v_has_note = 'yes' THEN si.note IS NOT NULL AND si.note <> ''
          WHEN v_has_note = 'no'  THEN si.note IS NULL OR si.note = ''
          ELSE true
        END;

  SELECT jsonb_agg(jsonb_build_object('value', uc.key, 'label', uc.short_label) ORDER BY uc.sort_order)
    INTO v_area_options
    FROM public.ui_copy uc
   WHERE uc.domain = 'area' AND uc.lang = 'es';

  SELECT jsonb_agg(jsonb_build_object('value', uc.key, 'label', uc.short_label) ORDER BY uc.sort_order)
    INTO v_format_options
    FROM public.ui_copy uc
   WHERE uc.domain = 'resource_format' AND uc.lang = 'es';

  v_has_note_options := jsonb_build_array(
    jsonb_build_object('value', 'yes', 'label', 'Con nota'),
    jsonb_build_object('value', 'no',  'label', 'Sin nota')
  );

  v_message := CASE
    WHEN v_count = 0 AND v_has_filters THEN 'Nada con estos filtros. Prob├Ī ajustar.'
    WHEN v_has_filters THEN v_count::text || ' de ' || v_total::text || ' guardados.'
    ELSE 'Ac├Ī est├Ī lo que fuiste guardando.'
  END;

  v_node_code := 'SANTUARIO_ENTRY';
  v_node      := public.lumi_get_node(v_node_code);

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         v_node_code,
    'message',      v_message,
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'item_list',
    'content', jsonb_build_object(
      'type',   'item_list',
      'source', 'sanctuary',
      'items',  v_items,
      'current_filters', jsonb_build_object(
        'area', v_area, 'format', v_format, 'has_note', v_has_note
      ),
      'filter_options', jsonb_build_object(
        'area',     coalesce(v_area_options, '[]'::jsonb),
        'format',   coalesce(v_format_options, '[]'::jsonb),
        'has_note', v_has_note_options
      )
    ),
    'state', jsonb_build_object(
      'contentSource', 'sanctuary',
      'moduleColor',   '#B88820'
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_open_sanctuary_item(p_user_id_text text, p_sanctuary_item_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id           uuid;
  v_sanctuary_item_id uuid;
  v_item              record;
  v_note              text;
  v_area              text;
  v_node_code         text;
  v_node              jsonb;
  v_actions_raw       jsonb;
  v_actions_final     jsonb := '[]'::jsonb;
  v_action            jsonb;
BEGIN
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;
  v_sanctuary_item_id := nullif(
    trim(both '''' from trim(coalesce(p_sanctuary_item_id_text, ''))),
    ''
  )::uuid;

  SELECT
    si.id AS sanctuary_item_id,
    si.resource_id,
    si.note,
    si.area,
    r.title,
    r.description_short,
    r.format,
    r.duration_min,
    r.source_kind,
    r.url
  INTO v_item
  FROM public.sanctuary_items si
  JOIN public.resources r ON r.id = si.resource_id
  WHERE si.id = v_sanctuary_item_id
    AND si.user_id = v_user_id
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN public.lumi_get_node('SANCTUARY_EMPTY');
  END IF;

  v_note := coalesce(v_item.note, '');
  v_area := coalesce(v_item.area::text, '');

  -- Decidir el c├│digo del nodo seg├║n haya nota o no
  v_node_code := CASE
    WHEN v_note <> '' THEN 'SANCTUARY_ITEM_WITH_NOTE'
    ELSE 'SANCTUARY_ITEM_WITHOUT_NOTE'
  END;
  v_node := public.lumi_get_node(v_node_code);

  -- Hidratar los `value` contextuales en las actions que vienen del nodo
  v_actions_raw := coalesce(v_node->'actions', '[]'::jsonb);
  FOR v_action IN SELECT * FROM jsonb_array_elements(v_actions_raw)
  LOOP
    -- Inyectar value seg├║n la acci├│n
    IF v_action->>'action' = 'open_note_editor' THEN
      v_action := v_action || jsonb_build_object('value', v_item.resource_id::text);
    ELSIF v_action->>'action' = 'confirm_remove_from_sanctuary' THEN
      v_action := v_action || jsonb_build_object('value', v_item.sanctuary_item_id::text);
    END IF;
    v_actions_final := v_actions_final || jsonb_build_array(v_action);
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'code', v_node_code,
    'message', coalesce(v_node->>'message',
      CASE WHEN v_note = '' THEN
        'Aqu├Ł est├Ī. Todav├Ła no escribiste una nota ŌĆö pod├®s hacerlo cuando quieras.'
      ELSE
        'Aqu├Ł est├Ī. Solo vos pod├®s leer esto.'
      END),
    'actions', v_actions_final,
    'content_type', 'sanctuary_detail',
    'content', jsonb_build_object(
      'type',               'sanctuary_detail',
      'sanctuary_item_id',  v_item.sanctuary_item_id::text,
      'resource_id',        v_item.resource_id::text,
      'title',              v_item.title,
      'description_short',  coalesce(v_item.description_short, ''),
      'format',             coalesce(v_item.format::text, 'ŌĆö'),
      'duration_min',       coalesce(v_item.duration_min::text, 'ŌĆö'),
      'source_kind',        coalesce(v_item.source_kind, 'external_url'),
      'url',                coalesce(v_item.url, ''),
      'note',               v_note,
      'area',               v_area,
      'has_note',           v_note <> '',
      'has_area',           v_area <> ''
    ),
    'state', jsonb_build_object(
      'currentResourceId',       v_item.resource_id::text,
      'currentSanctuaryItemId',  v_item.sanctuary_item_id::text,
      'resourceSourceKind',      coalesce(v_item.source_kind, 'external_url'),
      'activeUrl',               coalesce(v_item.url, ''),
      'contentSource',           'sanctuary',
      'moduleColor',             '#B88820',
      'spacesMenuOpen',          false,
      'filterPanelOpen',         false
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_remove_from_sanctuary(p_user_id_text text, p_sanctuary_item_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_user_id uuid;
  v_sanctuary_item_id uuid;
begin
  v_user_id := nullif(trim(p_user_id_text), '')::uuid;

  v_sanctuary_item_id := nullif(
    trim(both '''' from trim(coalesce(p_sanctuary_item_id_text, ''))),
    ''
  )::uuid;

  delete from public.sanctuary_items
  where id = v_sanctuary_item_id
    and user_id = v_user_id;

  return public.lumi_get_sanctuary(v_user_id);
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_resource_viewer_active(p_content_type text DEFAULT 'external_fallback'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_node jsonb;
  v_type text;
begin
  v_type := coalesce(nullif(trim(p_content_type), ''), 'external_fallback');
  v_node := public.lumi_get_node('RESOURCE_VIEWER_ACTIVE');

  return v_node
    || jsonb_build_object(
      'content_type', v_type,
      'content', jsonb_build_object('type', v_type)
    );
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_resource_viewer_active(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_source_kind text;
  v_resource_id uuid;
  v_user_id     uuid;
  v_source      text;
  v_session_id  uuid;
  v_result      jsonb;
  v_resource    record;
BEGIN
  v_source_kind := coalesce(nullif(trim(p_params->>'source_kind'), ''), 'external_fallback');
  v_resource_id := nullif(trim(p_params->>'resource_id'), '')::uuid;
  v_user_id     := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_source      := coalesce(nullif(trim(p_params->>'source'), ''), 'lumi');
  v_session_id  := nullif(trim(p_params->>'session_id'), '')::uuid;  -- ŌŚĆ NUEVO

  -- ŌŚĆ NUEVO: registrar apertura como punto ├║nico (solo si hay sesi├│n)
  IF v_session_id IS NOT NULL AND v_resource_id IS NOT NULL THEN
    PERFORM public.gaia_submit_session_action(
      p_session_id         := v_session_id,
      p_chosen_resource_id := v_resource_id,
      p_feedback           := NULL,
      p_saved              := false,
      p_action             := 'opened'::gaia_action_type
    );
  END IF;

  -- Resolver el envelope base
  v_result := public.lumi_resource_viewer_active(v_source_kind);

  -- Enriquecer el content con datos del recurso si tenemos ID
  IF v_resource_id IS NOT NULL THEN
    SELECT r.title, r.url, r.source_kind, r.format, r.duration_min
    INTO v_resource
    FROM public.resources r
    WHERE r.id = v_resource_id;
    IF FOUND THEN
      v_result := jsonb_set(v_result, '{content}',
        (v_result->'content') || jsonb_build_object(
          'title',        coalesce(v_resource.title, ''),
          'activeUrl',    coalesce(v_resource.url, ''),
          'source_kind',  coalesce(v_resource.source_kind, 'external_url'),
          'resource_id',  v_resource_id::text
        )
      );
      v_result := jsonb_set(v_result, '{state}',
        coalesce(v_result->'state', '{}'::jsonb) || jsonb_build_object(
          'currentResourceId',  v_resource_id::text,
          'activeUrl',          coalesce(v_resource.url, ''),
          'resourceSourceKind', coalesce(v_resource.source_kind, 'external_url'),
          'contentSource',      v_source
        )
      );
    END IF;
  END IF;

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_restore_node(p_user_id_text text, p_code text, p_context jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_source text := coalesce(p_context->>'source', '');
  v_resource_id text := coalesce(p_context->>'resource_id', '');
  v_session_id text := coalesce(p_context->>'session_id', '');
  v_sanctuary_item_id text := coalesce(p_context->>'sanctuary_item_id', '');
begin
  if p_code = 'SANCTUARY_DETAIL' and v_sanctuary_item_id <> '' then
    return public.lumi_open_sanctuary_item(
      p_user_id_text,
      v_sanctuary_item_id
    );
  end if;

  if p_code in (
    'RESOURCE_FROM_LUMI',
    'RESOURCE_FROM_FUENTE',
    'RESOURCE_FROM_SANCTUARY'
  ) and v_resource_id <> '' then
    return public.lumi_open_resource(
      p_user_id_text,
      v_resource_id,
      v_source,
      v_session_id
    );
  end if;

  return public.lumi_get_node(p_code);
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_save_faro(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id   uuid;
  v_area_text text;
  v_area      life_area;
  v_faro_text text;
BEGIN
  v_user_id   := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_area_text := nullif(trim(coalesce(p_params->>'area', '')), '');
  v_faro_text := coalesce(p_params->>'faro_text', '');

  IF v_user_id IS NULL OR v_area_text IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'missing_user_id_or_area');
  END IF;

  -- Cast seguro del enum
  BEGIN
    v_area := v_area_text::life_area;
  EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('ok', false, 'error', 'invalid_area');
  END;

  -- Si el texto viene vac├Ło ŌåÆ eliminar el faro (limpieza can├│nica)
  IF trim(v_faro_text) = '' THEN
    DELETE FROM public.user_area_faros
    WHERE user_id = v_user_id AND area = v_area;
  ELSE
    INSERT INTO public.user_area_faros(user_id, area, faro_text, updated_at)
    VALUES (v_user_id, v_area, trim(v_faro_text), now())
    ON CONFLICT (user_id, area)
    DO UPDATE SET faro_text  = excluded.faro_text,
                  updated_at = now();
  END IF;

  -- Silencio can├│nico: solo ok, sin envelope
  RETURN jsonb_build_object('ok', true, 'state', '{}'::jsonb);
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_save_note(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id           uuid;
  v_resource_id       uuid;
  v_note              text;
  v_area_text         text;
  v_area              life_area;
  v_sanctuary_item_id uuid;
BEGIN
  v_user_id     := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_resource_id := nullif(trim(p_params->>'resource_id'), '')::uuid;
  v_note        := coalesce(p_params->>'note', '');
  v_area_text   := nullif(trim(coalesce(p_params->>'area', '')), '');

  IF v_user_id IS NULL OR v_resource_id IS NULL THEN
    RETURN public.lumi_open_sanctuary(p_params);
  END IF;

  -- Cast seguro del enum life_area
  IF v_area_text IS NOT NULL THEN
    BEGIN
      v_area := v_area_text::life_area;
    EXCEPTION WHEN OTHERS THEN
      v_area := NULL;  -- valor inv├Īlido ŌåÆ ├Īrea vac├Ła (no rompe)
    END;
  END IF;

  -- UPDATE: guardar nota + ├Īrea (vac├Łos ŌåÆ NULL)
  UPDATE public.sanctuary_items
  SET note       = nullif(v_note, ''),
      area       = v_area,
      updated_at = now()
  WHERE user_id = v_user_id AND resource_id = v_resource_id
  RETURNING id INTO v_sanctuary_item_id;

  IF v_sanctuary_item_id IS NULL THEN
    -- El item no existe en sanctuary ŌåÆ volver al listado
    RETURN public.lumi_open_sanctuary(p_params);
  END IF;

  -- Devolver el detalle actualizado v├Ła la cadena can├│nica
  RETURN public.lumi_open_sanctuary_item(jsonb_build_object(
    'user_id',            v_user_id::text,
    'sanctuary_item_id',  v_sanctuary_item_id::text
  ));
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_share_resource_text(p_title text DEFAULT ''::text, p_format text DEFAULT ''::text, p_duration text DEFAULT ''::text, p_url text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_node jsonb;
  v_content jsonb;
  v_title text := trim(coalesce(p_title, ''));
  v_format text := trim(coalesce(p_format, ''));
  v_duration text := trim(coalesce(p_duration, ''));
  v_url text := trim(coalesce(p_url, ''));
  v_meta text := '';
  v_text text;
begin
  v_node := public.lumi_get_node('SHARE_RESOURCE_TEXT');

  if v_format <> '' then
    v_meta := v_format;
  end if;

  if v_duration <> '' then
    v_meta := case
      when v_meta = '' then v_duration || ' min'
      else v_meta || ' ┬Ę ' || v_duration || ' min'
    end;
  end if;

  v_text :=
    'Te comparto algo que me pareci├│ valioso. Quiz├Īs tambi├®n te sirva:' ||
    E'\n\n' ||
    case when v_title <> '' then v_title || E'\n' else '' end ||
    case when v_meta <> '' then v_meta || E'\n' else '' end ||
    case when v_url <> '' then E'\n' || v_url else '' end;

  v_content := jsonb_build_object(
    'type', 'share_text',
    'title', v_title,
    'format', v_format,
    'duration', v_duration,
    'url', v_url,
    'text', v_text
  );

  return jsonb_set(v_node, '{content}', v_content);
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_share_text_copied(p_text text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_node jsonb;
  v_content jsonb;
begin
  v_node := public.lumi_get_node('SHARE_RESOURCE_TEXT');

  v_content := jsonb_build_object(
    'type', 'share_text',
    'title', '',
    'format', '',
    'duration', '',
    'url', '',
    'text', coalesce(p_text, ''),
    'copied', true
  );

  v_node := jsonb_set(v_node, '{message}', to_jsonb('Listo. Ya ten├®s el texto disponible para pegarlo y compartirlo donde quieras.'::text));
  v_node := jsonb_set(v_node, '{content}', v_content);

  return v_node;
end;
$function$

CREATE OR REPLACE FUNCTION public.lumi_start_checkin(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_node    jsonb;
  v_options jsonb;
  v_intro   text;
BEGIN
  v_node := public.lumi_get_node('CHECKIN_STATE');

  SELECT jsonb_agg(
    jsonb_build_object('value', uc.key, 'label', uc.short_label, 'hint', uc.subtitle)
    ORDER BY uc.sort_order, uc.key
  ) INTO v_options
  FROM public.ui_copy uc
  WHERE uc.domain = 'state' AND uc.lang = 'es';

  v_node := jsonb_set(v_node, '{content,options}', coalesce(v_options, '[]'::jsonb));

  v_intro := public.lumi_get_message('intro', 'checkin_intro');

  RETURN v_node || jsonb_build_object(
    'message', coalesce(v_intro, v_node->>'message', '┬┐C├│mo est├Īs hoy?'),
    'state',   jsonb_build_object('checkinState', '', 'checkinArea', '', 'checkinTime', '')
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_start_recommendation(p_user_id uuid, p_state gaia_state, p_area life_area, p_time_bucket time_bucket)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_session     jsonb;
  v_session_id  uuid;
  v_fallback    int;
  v_had_no_match boolean;
  v_recs        jsonb;
  v_resource_id uuid;
  v_card        jsonb;
  v_node_code   text;
  v_node        jsonb;
BEGIN
  v_session := public.gaia_create_session_and_recommendations(
    p_user_id, 'propose', p_state, p_area, p_time_bucket
  );
  v_session_id   := (v_session->>'session_id')::uuid;
  v_fallback     := coalesce((v_session->>'fallback_level')::int, 99);
  v_had_no_match := coalesce((v_session->>'had_no_match')::boolean, false);
  v_recs         := coalesce(v_session->'recommendations', '[]'::jsonb);

  -- ŌöĆŌöĆŌöĆ No-match can├│nico: rutear a NO_MATCH_OFFER ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  -- Si el motor expl├Łcitamente marc├│ no-match O no hay recs,
  -- presentar las 3 opciones de salida noble.
  IF v_had_no_match OR jsonb_array_length(v_recs) = 0 THEN
    v_node := public.lumi_get_node('NO_MATCH_OFFER');
    RETURN jsonb_build_object(
      'ok',           true,
      'code',         'NO_MATCH_OFFER',
      'message',      coalesce(v_session->>'gaia_copy', v_node->>'message',
                               'Hoy no tengo algo perfecto para esto.'),
      'actions',      coalesce(v_node->'actions', '[]'::jsonb),
      'content_type', 'empty_presence',
      'content',      jsonb_build_object('type', 'empty_presence'),
      'state',        jsonb_build_object(
                        'currentSessionId',  v_session_id::text,
                        'currentResourceId', '',
                        'contentSource',     '',
                        'moduleColor',       '#7860E0'
                      )
    );
  END IF;

  -- ŌöĆŌöĆŌöĆ Camino feliz: hay recomendaci├│n ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
  v_resource_id := (v_recs->0->>'resource_id')::uuid;
  v_card := public.gaia_get_resource_card(p_user_id, v_resource_id, v_session_id);

  v_node_code := CASE
    WHEN v_fallback = 0 THEN 'REC_PROPOSAL_HIGH'
    WHEN v_fallback <= 2 THEN 'REC_PROPOSAL_MED'
    ELSE 'REC_PROPOSAL_LOW'
  END;
  v_node := public.lumi_get_node(v_node_code);

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         v_node->>'code',
    'message',      coalesce(v_session->>'gaia_copy', v_node->>'message'),
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'resource_card',
    'content', coalesce(v_card, '{}'::jsonb) ||
      jsonb_build_object(
        'type',        'resource_card',
        'resource_id', v_resource_id::text,
        'session_id',  v_session_id::text,
        'is_from',     'lumi'
      ),
    'state', jsonb_build_object(
      'currentSessionId',          v_session_id::text,
      'currentResourceId',         v_resource_id::text,
      'resourceSourceKind',        coalesce(v_card->>'source_kind', 'external_url'),
      'activeUrl',                 coalesce(v_card->>'url', ''),
      'lastRecommendationPosition', 1,
      'contentSource',             'lumi'
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_area(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_value   text := coalesce(p_params->>'checkin_area', '');
  v_node    jsonb;
  v_options jsonb;
BEGIN
  IF v_value = '' THEN
    RETURN public.lumi_submit_checkin_state(p_params);
  END IF;

  v_node := public.lumi_get_node('CHECKIN_TIME');

  SELECT jsonb_agg(
           jsonb_build_object(
             'value', uc.key,
             'label', uc.short_label,
             'hint',  uc.subtitle
           ) ORDER BY uc.sort_order, uc.key
         )
    INTO v_options
    FROM public.ui_copy uc
   WHERE uc.domain = 'time_bucket' AND uc.lang = 'es';

  v_node := jsonb_set(v_node, '{content,options}', coalesce(v_options, '[]'::jsonb));

  RETURN v_node || jsonb_build_object(
    'state', jsonb_build_object('checkinArea', v_value)
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_state(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_value   text := coalesce(p_params->>'checkin_state', '');
  v_node    jsonb;
  v_options jsonb;
BEGIN
  IF v_value = '' THEN
    RETURN public.lumi_start_checkin(p_params);
  END IF;

  v_node := public.lumi_get_node('CHECKIN_AREA');

  SELECT jsonb_agg(
           jsonb_build_object(
             'value', uc.key,
             'label', uc.short_label,
             'hint',  uc.subtitle
           ) ORDER BY uc.sort_order, uc.key
         )
    INTO v_options
    FROM public.ui_copy uc
   WHERE uc.domain = 'area' AND uc.lang = 'es';

  v_node := jsonb_set(v_node, '{content,options}', coalesce(v_options, '[]'::jsonb));

  RETURN v_node || jsonb_build_object(
    'state', jsonb_build_object('checkinState', v_value)
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_checkin_time(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_value    text := coalesce(p_params->>'checkin_time', '');
  v_params   jsonb;
  v_result   jsonb;
  v_guidance text;
BEGIN
  IF v_value = '' THEN
    RETURN public.lumi_submit_checkin_area(p_params);
  END IF;

  v_params := p_params || jsonb_build_object('checkin_time', v_value);
  v_result := public.lumi_start_recommendation(v_params);

  v_guidance := public.lumi_get_message('guidance', 'before_suggestions');

  RETURN v_result || jsonb_build_object(
    'message', coalesce(v_guidance, v_result->>'message', 'Tengo algunas ideas para este momento.'),
    'state',   coalesce(v_result->'state', '{}'::jsonb)
                 || jsonb_build_object('checkinTime', v_value)
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_contribution(p_user_id uuid, p_title text, p_url text DEFAULT ''::text, p_why text DEFAULT ''::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id uuid;
BEGIN
  IF trim(p_title) = '' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'title_required');
  END IF;

  INSERT INTO public.resource_proposals (
    user_id, url, title, rationale, lang
  ) VALUES (
    p_user_id,
    CASE WHEN trim(p_url) = '' THEN 'sin_url' ELSE trim(p_url) END,
    trim(p_title),
    CASE WHEN trim(p_why) = '' THEN NULL ELSE trim(p_why) END,
    'es'
  )
  RETURNING id INTO v_id;

  RETURN jsonb_build_object('ok', true, 'proposal_id', v_id::text);
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_name(p_params jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id    uuid;
  v_first_name text;
  v_node       jsonb;
  v_message    text;
BEGIN
  v_user_id    := nullif(trim(p_params->>'user_id'), '')::uuid;
  v_first_name := nullif(trim(p_params->>'first_name'), '');

  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'missing_user_id');
  END IF;

  IF v_first_name IS NOT NULL AND length(v_first_name) > 0 THEN
    UPDATE public.users 
    SET first_name = substring(v_first_name from 1 for 40), has_visited = true 
    WHERE id = v_user_id;
    v_message := 'Hola, ' || substring(v_first_name from 1 for 40) 
              || '. No hace falta que sepas qu├® necesit├Īs. Podemos empezar por algo peque├▒o.';
  ELSE
    UPDATE public.users SET has_visited = true WHERE id = v_user_id;
    v_message := 'No hace falta que sepas qu├® necesit├Īs. Podemos empezar por algo peque├▒o.';
  END IF;

  v_node := public.lumi_get_node('HOME_DEFAULT');

  RETURN jsonb_build_object(
    'ok',           true,
    'code',         'HOME_DEFAULT',
    'message',      v_message,
    'actions',      coalesce(v_node->'actions', '[]'::jsonb),
    'content_type', 'empty_presence',
    'content',      jsonb_build_object(
                      'type', 'empty_presence',
                      'culture_phrase', coalesce(public.lumi_get_message('culture_phrase', 'first_contact'), '')
                    ),
    'state', jsonb_build_object(
      'contentSource', '', 'moduleColor', '#7860E0',
      'currentSessionId', '', 'currentResourceId', '', 'currentSanctuaryItemId', ''
    )
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.lumi_submit_session_action(p_session_id_text text DEFAULT ''::text, p_resource_id_text text DEFAULT ''::text, p_feedback text DEFAULT ''::text, p_saved boolean DEFAULT false)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_session_id uuid;
  v_resource_id uuid;
begin
  v_session_id := nullif(trim(both '''' from trim(coalesce(p_session_id_text, ''))), '')::uuid;
  v_resource_id := nullif(trim(both '''' from trim(coalesce(p_resource_id_text, ''))), '')::uuid;

  if v_session_id is null or v_resource_id is null then
    return jsonb_build_object('ok', false, 'reason', 'missing_session_or_resource');
  end if;

  return public.gaia_submit_session_action(
    p_session_id := v_session_id,
    p_chosen_resource_id := v_resource_id,
    p_feedback := nullif(trim(p_feedback), '')::feedback_type,
    p_saved := coalesce(p_saved, false)
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  new.updated_at = now();
  return new;
end;
$function$
